            >
              <ActionTooltip
                label={`Open ${orchestratorLabel} terminal`}
                trigger={
                  <SidebarMenuButton
                    render={<button type="button" />}
                    isActive={selectionKey === props.selectedTerminalSessionKey}
                    size="sm"
                    className="h-7 w-full ps-10 pe-4 font-normal text-foreground hover:text-foreground active:text-foreground data-[active=true]:text-foreground"
                    onClick={() =>
                      props.onOrchestratorSessionSelect(selectionKey)
                    }
